class Solution(object):
    def processStr(self, s):
        result = []
        for c in s:
            if c.islower():
                result.append(c)
            elif c == '*':
                if result:
                    result.pop()
            elif c == '#':
                result = result + result  # duplicate
            elif c == '%':
                result.reverse()
        return ''.join(result)
